value_map.by value:
void modify(int x) {
    x = 99;  // modifies the local copy only
    std::cout << "(by value: x is a separate copy; nothing links it to val)"
              << std::endl;
}

int main() {
    int val = 42;
    std::cout << "before: val = " << val << std::endl;
    modify(val);
    std::cout << "after:  val = " << val << std::endl;
    <<HARNESS>>
}

value_map.by pointer:
void modify(int* x) {
    *x = 99;  // write THROUGH the pointer into the caller's val
    printf("PTRDATA: type=raw ptr_addr=%p target_addr=%p target_val=%d\n",
           (void*)&x, (void*)x, *x);
}

int main() {
    int val = 42;
    std::cout << "before: val = " << val << std::endl;
    modify(&val);
    std::cout << "after:  val = " << val << std::endl;
    <<HARNESS>>
}

value_map.by reference:
void modify(int& x) {
    x = 99;  // x is another name for val — same object
    printf("PTRDATA: type=ref ref_addr=%p target_addr=%p target_val=%d\n",
           (void*)&x, (void*)&x, x);
}

int main() {
    int val = 42;
    std::cout << "before: val = " << val << std::endl;
    modify(val);
    std::cout << "after:  val = " << val << std::endl;
    <<HARNESS>>
}
